type Grid = number[][];

const countNeighbors = (grid: Grid, row: number, col: number): number => {
  let count = 0;
  const rows = grid.length;
  const cols = grid[0]?.length ?? 0;
  for (let r = row - 1; r <= row + 1; r++) {
    for (let c = col - 1; c <= col + 1; c++) {
      if (r === row && c === col) continue;
      if (r >= 0 && r < rows && c >= 0 && c < cols) {
        count += grid[r][c];
      }
    }
  }
  return count;
};

const willCellLive = (alive: boolean, neighbors: number): boolean =>
  (alive && (neighbors === 2 || neighbors === 3)) || (!alive && neighbors === 3);

export function nextGeneration(grid: Grid): Grid {
  if (grid.length === 0) return [];
  const rows = grid.length;
  const cols = grid[0].length;
  const next: Grid = [];
  for (let r = 0; r < rows; r++) {
    const nextRow: number[] = [];
    for (let c = 0; c < cols; c++) {
      const neighbors = countNeighbors(grid, r, c);
      const alive = grid[r][c] === 1;
      nextRow.push(willCellLive(alive, neighbors) ? 1 : 0);
    }
    next.push(nextRow);
  }
  return next.filter(row => row.some(cell => cell === 1));
}

